#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding stroke-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    ethnicity:string! \
    handedness:string! \
    pre_stroke_mrs_score:int \
    pre_stroke_independence:string! \
    emergency_contact_name:string! \
    emergency_contact_phone:string! \
    --htmx

cargo loco generate scaffold assessment_symptom_onset \
    assessment:references \
    symptom_onset_time:ts \
    last_known_well_time:ts \
    onset_witnessed:string! \
    wake_up_stroke:string! \
    onset_setting:string! \
    onset_activity:text! \
    symptom_progression:string! \
    initial_symptoms:text! \
    headache_at_onset:string! \
    seizure_at_onset:string! \
    vomiting_at_onset:string! \
    loss_of_consciousness:string! \
    time_from_onset_to_arrival_minutes:int \
    --htmx

cargo loco generate scaffold assessment_level_of_consciousness \
    assessment:references \
    nihss_1a_loc:int \
    nihss_1b_loc_questions:int \
    nihss_1c_loc_commands:int \
    gcs_eye:int \
    gcs_verbal:int \
    gcs_motor:int \
    gcs_total:int \
    orientation_notes:text! \
    --htmx

cargo loco generate scaffold assessment_best_gaze_visual \
    assessment:references \
    nihss_2_best_gaze:int \
    nihss_3_visual_fields:int \
    gaze_deviation_direction:string! \
    forced_eye_deviation:string! \
    pupil_left_mm:double \
    pupil_right_mm:double \
    pupil_left_reactive:string! \
    pupil_right_reactive:string! \
    visual_field_deficit_type:string! \
    visual_deficit_notes:text! \
    --htmx

cargo loco generate scaffold assessment_facial_palsy_motor \
    assessment:references \
    nihss_4_facial_palsy:int \
    nihss_5a_motor_arm_left:int \
    nihss_5b_motor_arm_right:int \
    nihss_6a_motor_leg_left:int \
    nihss_6b_motor_leg_right:int \
    facial_droop_side:string! \
    pronator_drift:string! \
    motor_deficit_pattern:string! \
    affected_side:string! \
    --htmx

cargo loco generate scaffold assessment_limb_ataxia_sensory \
    assessment:references \
    nihss_7_limb_ataxia:int \
    nihss_8_sensory:int \
    ataxia_present_left_arm:string! \
    ataxia_present_right_arm:string! \
    ataxia_present_left_leg:string! \
    ataxia_present_right_leg:string! \
    finger_to_nose_test:string! \
    heel_to_shin_test:string! \
    sensory_loss_pattern:string! \
    sensory_loss_side:string! \
    sensory_modalities_affected:text! \
    --htmx

cargo loco generate scaffold assessment_language_dysarthria \
    assessment:references \
    nihss_9_best_language:int \
    nihss_10_dysarthria:int \
    aphasia_type:string! \
    speech_fluency:string! \
    comprehension_intact:string! \
    repetition_intact:string! \
    naming_intact:string! \
    reading_intact:string! \
    writing_intact:string! \
    dysarthria_severity:string! \
    language_notes:text! \
    --htmx

cargo loco generate scaffold assessment_extinction_inattention \
    assessment:references \
    nihss_11_extinction_inattention:int \
    visual_neglect:string! \
    tactile_neglect:string! \
    auditory_neglect:string! \
    anosognosia:string! \
    line_bisection_abnormal:string! \
    neglect_notes:text! \
    --htmx

cargo loco generate scaffold assessment_risk_factors \
    assessment:references \
    hypertension:string! \
    diabetes:string! \
    atrial_fibrillation:string! \
    atrial_fibrillation_anticoagulated:string! \
    hyperlipidaemia:string! \
    previous_stroke:string! \
    previous_stroke_details:text! \
    previous_tia:string! \
    carotid_stenosis:string! \
    coronary_artery_disease:string! \
    heart_failure:string! \
    valvular_heart_disease:string! \
    smoking_status:string! \
    alcohol_excess:string! \
    illicit_drug_use:string! \
    family_history_stroke:string! \
    obstructive_sleep_apnoea:string! \
    oral_contraceptive_hrt:string! \
    additional_risk_factors:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    anticoagulant_use:string! \
    anticoagulant_name:text! \
    last_anticoagulant_dose_time:ts \
    inr_value:double \
    antiplatelet_use:string! \
    antiplatelet_name:text! \
    antihypertensive_use:string! \
    antihypertensive_details:text! \
    statin_use:string! \
    diabetic_medication:string! \
    diabetic_medication_details:text! \
    recent_thrombolytic:string! \
    other_medications:text! \
    known_drug_allergies:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    nihss_total_score:int \
    stroke_severity:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
